using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class ApiTools
{
    [McpServerTool, Description("Fetches data from an external API for the given resource path.")]
    public static async Task<string> FetchData(
        IHttpClientFactory httpClientFactory,
        [Description("The API resource path to query (e.g. \"users/42\").")] string resourcePath,
        CancellationToken cancellationToken = default)
    {
        using var client = httpClientFactory.CreateClient("ExternalApi");

        using var response = await client.GetAsync(resourcePath, cancellationToken);
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(
            await response.Content.ReadAsStreamAsync(cancellationToken),
            cancellationToken: cancellationToken);

        return JsonSerializer.Serialize(doc.RootElement, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public sealed class SummarizationPrompts
{
    [McpServerPrompt, Description("Generates a concise summary of the provided text.")]
    public static IEnumerable<ChatMessage> Summarize(
        [Description("The text content to summarize.")] string content,
        [Description("Desired detail level: brief, standard, or detailed.")] string detailLevel = "standard")
    {
        yield return new ChatMessage(
            ChatRole.User,
            $$"""
            Summarize the following text at a {{detailLevel}} level of detail.
            Return only the summary with no preamble.

            ---
            {{content}}
            ---
            """);
    }
}

